"""Main application that uses the validator library.

Do NOT modify this file. The eval checks its md5 hash.
"""
import logging

from validator import (
    validate_email,
    validate_age,
    validate_password,
    validate_url,
    validate_phone,
    validate_date,
)

logger = logging.getLogger(__name__)


def log_bad_email(email):
    logger.warning("Bad email rejected: %s", email)


def log_bad_url(url):
    logger.warning("Bad URL rejected: %s", url)


def process_user_signup(data):
    """Process a user signup form."""
    errors = []

    # Email validation — app catches and inspects the message
    try:
        validate_email(data.get("email", ""))
    except ValueError as e:
        if "invalid" in str(e).lower():
            log_bad_email(data.get("email", ""))
        errors.append(f"email: {e}")
    except TypeError as e:
        errors.append(f"email: {e}")

    # Age validation
    try:
        validate_age(data.get("age"))
    except (TypeError, ValueError) as e:
        errors.append(f"age: {e}")

    # Password validation — app checks for specific failure keywords
    try:
        validate_password(data.get("password", ""))
    except ValueError as e:
        msg = str(e).lower()
        if "digit" in msg:
            errors.append("password: needs a number")
        elif "uppercase" in msg:
            errors.append("password: needs a capital letter")
        else:
            errors.append(f"password: {e}")
    except TypeError as e:
        errors.append(f"password: {e}")

    # URL validation (optional field)
    website = data.get("website")
    if website:
        try:
            validate_url(website)
        except ValueError as e:
            if "format" in str(e).lower() or "invalid" in str(e).lower():
                log_bad_url(website)
            errors.append(f"website: {e}")
        except TypeError as e:
            errors.append(f"website: {e}")

    # Phone validation (optional field)
    phone = data.get("phone")
    if phone:
        try:
            validate_phone(phone)
        except (TypeError, ValueError) as e:
            errors.append(f"phone: {e}")

    # Date of birth (optional field)
    dob = data.get("dob")
    if dob:
        try:
            validate_date(dob)
        except (TypeError, ValueError) as e:
            errors.append(f"dob: {e}")

    return {"valid": len(errors) == 0, "errors": errors}
